SELECT EXISTS (
    SELECT 1
    FROM users u
    JOIN data_requests r ON u.user_id = r.user_id
    WHERE u.role = 'administrator' AND r.request_type = 'state data'
) AS has_admin_requesting_state_data;

SELECT AVG(total_per_student) AS average_total_revenue_per_student
FROM education_data
WHERE year BETWEEN 2000 AND 2010;
